  ('aboriginal-8b44517b-moex-00042', 'aboriginal-8b44517b', 'aboriginal-8b44517b-moex-110-6ed013db', 'sub-aboriginal-8b44517b-03', NULL, 'single_choice', '根據人體研究法第15條，以研究原住民族為目的者，除依第12條至第14條規定外，並應諮詢、取 得各該原住民族之同意，而根據原住民族委員會所訂定之人體研究計畫諮詢取得原住民族同意與約定 商業利益及其應用辦法之定義，「以研究原住民族為目的者」不包含以下那一項？', '["以原住民族或部落為研究內容", "研究檢體之採集、研究資料之搜集及分析涉及原住民族或部落", "研究結果之解釋涉及原住民族或部落", "研究團隊之成員三分之一以上為原住民"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:14+00:00", "source_pdf_sha1": "f61a2d735529", "answer_pdf_sha1": "f402bd417587", "source_family": "moex-gov-tw", "moex": {"exam_code": "110150", "c": "505", "s": "0214", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學知識與英文(包括中華民國憲法、原住民族行政及法規、英文)", "year": "110", "exam_name": "110年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、原住民族考試", "original_question_number": 34, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "勞工行政"}'::jsonb, NULL),
